parameters.jsCode:
const opportunityData = $node["Get Qualified Opportunities"].json;

let pitchData;
try {
  const content = $json.message.content;
  pitchData = JSON.parse(content);
} catch (e) {
  console.error('Failed to parse pitch JSON:', e);
  // Fallback pitch
  pitchData = {
    subject: `Speaking Opportunity: ${opportunityData.event_name}`,
    opener: `Hi ${opportunityData.organizer_name || 'there'},`,
    body: `I noticed ${opportunityData.event_name} is seeking speakers. As founder of Seamlessly (hospitality tech platform helping 100+ venues increase revenue 30%), I'd love to share insights on mobile ordering and unified tech stacks. Would my expertise align with your audience?`,
    recommended_topic: 'The $25M Wait-Time Problem',
    ps: ''
  };
}

// Construct full email
const fullBody = `${pitchData.opener}\n\n${pitchData.body}${pitchData.ps ? '\n\nP.S. ' + pitchData.ps : ''}`;

// Add signature
const signature = `\n\nBest regards,\n[Your Name]\nFounder, Seamlessly\n[Your Email]\n[Your Phone]\n[Your Website]`;

return {
  ...opportunityData,
  pitch_subject: pitchData.subject,
  pitch_body: fullBody + signature,
  recommended_topic: pitchData.recommended_topic,
  status: opportunityData.score >= 18 ? 'Ready to Send - High Priority' : 'Ready to Send - Qualified',
  last_activity: new Date().toISOString()
};

